package core.logic.org.apache.syncope.core.logic;

@ Component public class ConfigurationLogic extends AbstractTransactionalLogic < AttrTO > { @ Autowired private ConfDAO confDAO ; @ Autowired private PlainSchemaDAO plainSchemaDAO ; @ Autowired private ConfigurationDataBinder binder ; @ Autowired private ContentExporter exporter ; @ Autowired private UserWorkflowAdapter uwfAdapter ; @ Autowired private GroupWorkflowAdapter gwfAdapter ; @ Autowired private AnyObjectWorkflowAdapter awfAdapter ; @ PreAuthorize ( "hasRole('" + StandardEntitlement . CONFIGURATION_DELETE + "')" ) public void delete ( final String schema ) { CPlainAttr conf = confDAO . find ( schema ) ; if ( conf == null ) { PlainSchema plainSchema = plainSchemaDAO . find ( schema ) ; if ( plainSchema == null ) { throw new NotFoundException ( "Configuration schema " + schema ) ; } } confDAO . delete ( schema ) ; } @ PreAuthorize ( "hasRole('" + StandardEntitlement . CONFIGURATION_LIST + "')" ) public List < AttrTO > list ( ) { return binder . getConfTO ( ) ; } @ PreAuthorize ( "isAuthenticated()" ) public AttrTO get ( final String schema ) { AttrTO result ; CPlainAttr conf = confDAO . find ( schema ) ; if ( conf == null ) { PlainSchema plainSchema = plainSchemaDAO . find ( schema ) ; if ( plainSchema == null ) { throw new NotFoundException ( "Configuration schema " + schema ) ; } result = new AttrTO ( ) ; result . setSchema ( schema ) ; } else { result = binder . getAttrTO ( conf ) ; } return result ; } @ PreAuthorize ( "hasRole('" + StandardEntitlement . CONFIGURATION_SET + "')" ) public void set ( final AttrTO value ) { confDAO . save ( binder . getAttr ( value ) ) ; } @ PreAuthorize ( "hasRole('" + StandardEntitlement . CONFIGURATION_EXPORT + "')" ) @ Transactional ( readOnly = true ) public void export ( final OutputStream os ) { try { exporter . export ( AuthContextUtils . getDomain ( ) , os , uwfAdapter . getPrefix ( ) , gwfAdapter . getPrefix ( ) , awfAdapter . getPrefix ( ) ) ; LOG . debug ( "Database content successfully exported" ) ; } catch ( Exception e ) { LOG . error ( "While exporting database content" , e ) ; } } @ Override protected AttrTO resolveReference ( final Method method , final Object ... args ) throws UnresolvedReferenceException { throw new UnresolvedReferenceException ( ) ; } }